// Time:  O(n)
// Space: O(n)

class Solution {
public:
    int binarySearchableNumbers(vector<int>& nums) {
        vector<int> right(size(nums) + 1, numeric_limits<int>::max());
        for (int i = size(nums); i >= 1; --i) {
            right[i - 1] = min(right[i], nums[i - 1]);
        }
        unordered_set<int> result;
        int left = numeric_limits<int>::min();
        for (int i = 0; i < size(nums); ++i) {
            if (left <= nums[i] && nums[i] <= right[i + 1]) {
                result.emplace(nums[i]);
            }
            left = max(left, nums[i]);
        }
        return size(result);
    }
};

# Time:  O(n)
# Space: O(n)

class Solution(object):
    def binarySearchableNumbers(self, nums):
        """
        :type nums: List[int]
        :rtype: int
        """
        right = [float("inf")]*(len(nums)+1)
        for i in reversed(xrange(1, len(nums)+1)):
            right[i-1] = min(right[i], nums[i-1])
        result, left = set(), float("-inf")
        for i in xrange(len(nums)):
            if left <= nums[i] <= right[i+1]:
                result.add(nums[i])
            left = max(left, nums[i])
        return len(result)
